import{_ as r,o as t,c as o,a0 as e}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"🔒 網頁端密碼箱白名單管理","description":"","frontmatter":{},"headers":[],"relativePath":"Web-Password-Lock.md","filePath":"Web-Password-Lock.md"}'),s={name:"Web-Password-Lock.md"};function n(l,a,i,c,d,_){return t(),o("div",null,[...a[0]||(a[0]=[e('<h1 id="🔒-網頁端密碼箱白名單管理" tabindex="-1">🔒 網頁端密碼箱白名單管理 <a class="header-anchor" href="#🔒-網頁端密碼箱白名單管理" aria-label="Permalink to &quot;🔒 網頁端密碼箱白名單管理&quot;">​</a></h1><p>安全密碼箱提供了強大的個人財產保護。除了在遊戲內設定密碼，您可以在網頁端管理授權白名單。</p><hr><h2 id="📁-1-密碼箱名冊" tabindex="-1">📁 1. 密碼箱名冊 <a class="header-anchor" href="#📁-1-密碼箱名冊" aria-label="Permalink to &quot;📁 1. 密碼箱名冊&quot;">​</a></h2><p>在 <strong>「密碼箱管理」</strong> 分頁中：</p><ul><li>系統會列出您在遊戲中放置並上鎖的全部密碼箱位置。</li><li>每張卡片會顯示該密碼箱的確切世界座標。</li></ul><hr><h2 id="👥-2-授權與白名單管理" tabindex="-1">👥 2. 授權與白名單管理 <a class="header-anchor" href="#👥-2-授權與白名單管理" aria-label="Permalink to &quot;👥 2. 授權與白名單管理&quot;">​</a></h2><p>您是密碼箱的唯一擁有者，您可以遠端進行以下操作：</p><ul><li><strong>新增白名單成員</strong>：在卡片中輸入好友的 Minecraft ID，將其加入開啟白名單。加入後，該玩家即使不輸入密碼，也可以直接打開該箱子！</li><li><strong>撤銷授權</strong>：點擊已授權玩家名字旁邊的 <strong><code>[ × ]</code></strong> 鈕，即可立刻撤銷該玩家的開啟權限。</li><li><strong>遠端變更密碼</strong>：點擊 <strong>「修改密碼」</strong>，輸入新密碼即可即時生效。</li><li><strong>註銷密碼鎖</strong>：點擊紅色的 <strong>「註銷密碼鎖」</strong>，徹底解除箱子的密碼鎖定防護，使其變回普通箱子。</li></ul>',10)])])}const p=r(s,[["render",n]]);export{g as __pageData,p as default};
